export default function KPIcards({ data }) {
  const total = data.reduce((sum, d) => sum + Number(d.monetary || 0), 0);

  return (
    <div>
      <h3>Total Revenue: ₹{total}</h3>
      <h3>Customers: {data.length}</h3>
    </div>
  );
}
